function bundleEvidence(overrides: Record<string, unknown> = {}): Record<string, unknown> {
  return {
    entry: { ...RECEIPT_ENTRY },
    leaf_index: 1,
    tree_size: 3,
    inclusion_proof: [...PROOF_INDEX_1],
    checkpoint: CP_BUNDLE3,
    ...overrides,
  }
}

/** Build a verifying `ots` anchor-evidence bundle + matching policy, per the
 * op-chain sequence documented in anchor.test.ts. Mirrors test_transparency.py's
 * `_working_ots_evidence`. */
function workingOtsEvidence(checkpointText: string): {
  evidence: Record<string, unknown>
  policy: AnchorPolicy
  headerTime: number
} {
  const noteBytes = parseCheckpoint(checkpointText).noteBytes
  const headerTime = 1700000000
  const headerHash = '3a'.repeat(32)
  const sibling = h('ab'.repeat(32))
  const prefix = h('cd'.repeat(16))
  let acc = sha256(noteBytes)
  acc = sha256(new Uint8Array([...acc, ...sibling]))
  acc = sha256(new Uint8Array([...prefix, ...acc]))
  const accHex = Array.from(acc).map((b) => b.toString(16).padStart(2, '0')).join('')
  const proof = {
    kind: 'ots',
    ops: [['append', bytesHex(sibling)], ['sha256'], ['prepend', bytesHex(prefix)], ['sha256']],
    header_merkle_root: accHex,
    header_time: headerTime,
    header_hash: headerHash,
  }
  const dummySigLine = '— test-key AA==\n'
  const evidence = { checkpoint: new TextDecoder().decode(noteBytes) + '\n' + dummySigLine, proofs: [proof] }
  const policy: AnchorPolicy = {
    pinnedHeaders: { [headerHash]: { headerHash, merkleRoot: accHex, time: headerTime } },
    crqcHorizon: null,
  }
  return { evidence, policy, headerTime }
}
function bytesHex(bytes: Uint8Array): string {
  return Array.from(bytes).map((b) => b.toString(16).padStart(2, '0')).join('')
}

function evaluate(
  evidence: unknown,
  overrides: Partial<{
    logKeys: LogKey[]
    expectedOrigin: string
    policy: AnchorPolicy
    expectedEntry: Record<string, unknown>
  }> = {},
) {
  return evaluateTransparency(evidence, {
    logKeys: overrides.logKeys ?? [HK_A],
    expectedOrigin: overrides.expectedOrigin ?? ORIGIN,
    policy: overrides.policy ?? noHorizonPolicy(),
    expectedEntry: overrides.expectedEntry ?? { ...RECEIPT_ENTRY },
  })
}

// --------------------------------------------------------------------------
// Happy path + decision order steps 1-3.
// --------------------------------------------------------------------------

describe('evaluateTransparency: happy path + steps 1-3', () => {
  it('returns logged for a fully valid bundle', () => {
    const result = evaluate(bundleEvidence())
    expect(result.transparency).toBe(TRANSPARENCY_LOGGED)
    expect(result.corroboration).toBe(CORROBORATION_LOGGED)
    expect(result.warnings).toEqual([])
  })

  it('flags an entry schema violation', () => {
    const evidence = bundleEvidence()
    const entry = { ...(evidence['entry'] as Record<string, unknown>) }
    delete entry['core_sha256']
    evidence['entry'] = entry
    const result = evaluate(evidence)
    expect(result.transparency).toBe(TRANSPARENCY_NOT_CHECKED)
    expect(result.corroboration).toBe(CORROBORATION_NONE)
    expect(result.warnings).toEqual(['entry_invalid'])
  })

  it('flags an entry mismatch against expected_entry', () => {
    const evidence = bundleEvidence({ entry: { ...RECEIPT_ENTRY, core_sha256: 'f'.repeat(64) } })
    const result = evaluate(evidence)
    expect(result.warnings).toEqual(['transparency_entry_mismatch'])
  })

  it('reports entry mismatch before checkpoint failure (ordering, not just one failure)', () => {
    const evidence = bundleEvidence({
      entry: { ...RECEIPT_ENTRY, core_sha256: 'f'.repeat(64) },
      checkpoint: 'not even a parseable checkpoint\n',
    })
    const result = evaluate(evidence)
    expect(result.warnings).toEqual(['transparency_entry_mismatch'])
  })

  it('flags a non-object entry field', () => {
    const result = evaluate(bundleEvidence({ entry: 'not-a-dict' }))
    expect(result.warnings).toEqual(['entry_invalid'])
  })

  it('flags a wrong-typed checkpoint field', () => {
    const result = evaluate(bundleEvidence({ checkpoint: 12345 }))
    expect(result.warnings).toEqual(['checkpoint_invalid'])
  })

  it('flags checkpoint verification failure for an unknown origin', () => {
    const result = evaluate(bundleEvidence(), { expectedOrigin: 'different-log/2026' })
    expect(result.warnings).toEqual(['checkpoint_verification_failed'])
  })

  it('flags a checkpoint signed by an untrusted key', () => {
    const otherKey: LogKey = { origin: ORIGIN, name: LOG_NAME, ed25519Pub: ed25519.getPublicKey(new Uint8Array(32).fill(5)), mldsaPub: new Uint8Array(1952) }
    const result = evaluate(bundleEvidence(), { logKeys: [otherKey] })
    expect(result.warnings).toEqual(['checkpoint_verification_failed'])
  })

  it('tries the next log key when the first does not verify (log-key rotation)', () => {
    const staleKey: LogKey = { origin: ORIGIN, name: LOG_NAME, ed25519Pub: ed25519.getPublicKey(new Uint8Array(32).fill(9)), mldsaPub: new Uint8Array(1952) }
    const result = evaluate(bundleEvidence(), { logKeys: [staleKey, HK_A] })
    expect(result.transparency).toBe(TRANSPARENCY_LOGGED)
    expect(result.warnings).toEqual([])
  })

  it('flags a wrong-typed leaf_index', () => {
    const result = evaluate(bundleEvidence({ leaf_index: '1' }))
    expect(result.warnings).toEqual(['leaf_index_invalid'])
  })

  it('rejects a bool leaf_index (JS naturally excludes this, unlike Python bool-is-int)', () => {
    const result = evaluate(bundleEvidence({ leaf_index: true }))
    expect(result.warnings).toEqual(['leaf_index_invalid'])
  })

  it('flags a wrong-typed tree_size', () => {
    const result = evaluate(bundleEvidence({ tree_size: '3' }))
    expect(result.warnings).toEqual(['tree_size_invalid'])
  })

  it('rejects a bool tree_size', () => {
    const result = evaluate(bundleEvidence({ tree_size: true }))
    expect(result.warnings).toEqual(['tree_size_invalid'])
  })

  it('flags a tree_size mismatch against the checkpoint', () => {
    const result = evaluate(bundleEvidence({ tree_size: 4 })) // checkpoint actually attests to tree_size=3
    expect(result.warnings).toEqual(['tree_size_mismatch'])
  })

  it('flags a non-list inclusion_proof', () => {
    // A JS array is the only "list-like" type; there is no analogous
    // ambiguous second sequence type to bypass Array.isArray with (unlike
    // Python's tuple-vs-list), so this exercises the same guard via an
    // object shape instead of a real alternate collection.
    const result = evaluate(bundleEvidence({ inclusion_proof: { 0: PROOF_INDEX_1[0], 1: PROOF_INDEX_1[1], length: 2 } }))
    expect(result.warnings).toEqual(['inclusion_proof_invalid'])
  })

  it('rejects an uppercase inclusion-proof entry', () => {
    const proof = [...PROOF_INDEX_1]
    proof[0] = proof[0]!.toUpperCase()
    const result = evaluate(bundleEvidence({ inclusion_proof: proof }))
    expect(result.warnings).toEqual(['inclusion_proof_invalid'])
  })

  it('rejects a wrong-length inclusion-proof entry', () => {
    const result = evaluate(bundleEvidence({ inclusion_proof: ['aa'.repeat(31)] }))
    expect(result.warnings).toEqual(['inclusion_proof_invalid'])
  })

  it('caps an oversized inclusion-proof list', () => {
    const result = evaluate(bundleEvidence({ inclusion_proof: Array.from({ length: 65 }, () => 'aa'.repeat(32)) }))
    expect(result.warnings).toEqual(['inclusion_proof_too_long'])
  })

  it('flags an inclusion proof that does not verify', () => {
    const result = evaluate(bundleEvidence({ leaf_index: 0 })) // well-formed proof, wrong leaf
    expect(result.warnings).toEqual(['inclusion_proof_invalid'])
  })
})

// --------------------------------------------------------------------------
// Step 4: prior checkpoint / consistency / equivocation.
// --------------------------------------------------------------------------

describe('evaluateTransparency: step 4 (prior checkpoint + equivocation)', () => {
  it('no warning when the prior checkpoint is consistent', () => {
    const evidence = bundleEvidence({ prior_checkpoint: CP_PRIOR2, consistency_proof: [...CONSISTENCY_PROOF_2TO3] })
    const result = evaluate(evidence)
    expect(result.transparency).toBe(TRANSPARENCY_LOGGED)
    expect(result.warnings).toEqual([])
  })

  it('detects equivocation on an inconsistent prior', () => {
    // A real proof for an honest 2->3 extension of a DIFFERENT tree, presented
    // against the bundle's actual (unrelated) current root: verify_consistency
    // must reject it.
    const evidence = bundleEvidence({ prior_checkpoint: CP_FORK2, consistency_proof: [...REAL_EXTENSION_PROOF] })
    const result = evaluate(evidence)
    expect(result.transparency).toBe(TRANSPARENCY_EQUIVOCATION_DETECTED)
    expect(result.corroboration).toBe(CORROBORATION_NONE)
    expect(result.warnings).toEqual(['log_equivocation_detected'])
  })

  it('equivocation survives a configured horizon', () => {
    const { evidence: anchorsEvidence, policy: policyBase, headerTime } = workingOtsEvidence(CP_BUNDLE3)
    const evidence = bundleEvidence({
      prior_checkpoint: CP_FORK2,
      consistency_proof: [...REAL_EXTENSION_PROOF],
      anchors: anchorsEvidence,
    })
    const policy: AnchorPolicy = { pinnedHeaders: policyBase.pinnedHeaders, crqcHorizon: headerTime - 1 }
    const result = evaluate(evidence, { policy })
    expect(result.transparency).toBe(TRANSPARENCY_EQUIVOCATION_DETECTED)
    expect(result.corroboration).toBe(CORROBORATION_NONE)
    expect(result.warnings).toEqual(['log_equivocation_detected'])
  })

  it('does not treat an unverifiable prior as equivocation (fail-safe, not a hard verdict)', () => {
    const evidence = bundleEvidence({ prior_checkpoint: CP_FORGED2, consistency_proof: [...CONSISTENCY_PROOF_2TO3] })
    const result = evaluate(evidence)
    expect(result.transparency).toBe(TRANSPARENCY_NOT_CHECKED)
    expect(result.corroboration).toBe(CORROBORATION_NONE)
    expect(result.warnings).toEqual(['prior_checkpoint_invalid'])
  })

  it('warns when the prior verifies but the consistency proof is missing', () => {
    const evidence = bundleEvidence({ prior_checkpoint: CP_PRIOR2 })
    const result = evaluate(evidence)
    expect(result.transparency).toBe(TRANSPARENCY_NOT_CHECKED)
    expect(result.warnings).toEqual(['consistency_proof_missing'])
  })

  it('flags a malformed consistency-proof shape', () => {
    const evidence = bundleEvidence({ prior_checkpoint: CP_PRIOR2, consistency_proof: ['not-hex'] })
    const result = evaluate(evidence)
    expect(result.warnings).toEqual(['consistency_proof_invalid'])
  })

  it('caps an oversized consistency-proof list (load-bearing, not just defense-in-depth)', () => {
    const evidence = bundleEvidence({
      prior_checkpoint: CP_PRIOR2,
      consistency_proof: Array.from({ length: 65 }, () => 'aa'.repeat(32)),
    })
    const result = evaluate(evidence)
    expect(result.warnings).toEqual(['consistency_proof_too_long'])
    expect(result.transparency).toBe(TRANSPARENCY_NOT_CHECKED)
  })

  it('flags a wrong-typed prior_checkpoint', () => {
    const result = evaluate(bundleEvidence({ prior_checkpoint: 42 }))
    expect(result.warnings).toEqual(['prior_checkpoint_invalid'])
  })

  it('flags an explicit null prior_checkpoint', () => {
    const result = evaluate(bundleEvidence({ prior_checkpoint: null }))
    expect(result.transparency).toBe(TRANSPARENCY_NOT_CHECKED)
    expect(result.corroboration).toBe(CORROBORATION_NONE)
    expect(result.warnings).toEqual(['prior_checkpoint_invalid'])
  })

  it('flags an explicit null consistency_proof', () => {
    const evidence = bundleEvidence({ prior_checkpoint: CP_PRIOR2, consistency_proof: null })
    const result = evaluate(evidence)
    expect(result.transparency).toBe(TRANSPARENCY_NOT_CHECKED)
    expect(result.corroboration).toBe(CORROBORATION_NONE)
    expect(result.warnings).toEqual(['consistency_proof_invalid'])
  })
})

// --------------------------------------------------------------------------
// Steps 6-7: anchors + CRQC horizon.
// --------------------------------------------------------------------------

describe('evaluateTransparency: steps 6-7 (anchors + horizon)', () => {
  it('sets anchored_before on a verified PQ anchor', () => {
    const { evidence: anchorsEvidence, policy, headerTime } = workingOtsEvidence(CP_BUNDLE3)
    const evidence = bundleEvidence({ anchors: anchorsEvidence })
    const result = evaluate(evidence, { policy })
    expect(result.transparency).toBe(`anchored_before:${iso8601(headerTime)}`)
    expect(result.corroboration).toBe(CORROBORATION_LOGGED)
    expect(result.warnings).toEqual([])
  })

  it('iso8601 KAT pins the helper independent of the brief arithmetic', () => {
    expect(iso8601(1700000000)).toBe('2023-11-14T22:13:20Z')
  })

  it('iso8601 renders the max supported pinned header time', () => {
    expect(iso8601(253402300799)).toBe('9999-12-31T23:59:59Z')
  })

  it('flags an explicit null anchors', () => {
    const result = evaluate(bundleEvidence({ anchors: null }))
    expect(result.transparency).toBe(TRANSPARENCY_NOT_CHECKED)
    expect(result.corroboration).toBe(CORROBORATION_NONE)
    expect(result.warnings).toEqual(['anchors_invalid'])
  })

  it('caps to not_checked when post-horizon unanchored (base standing alone never survives a horizon)', () => {
    const policy: AnchorPolicy = { pinnedHeaders: {}, crqcHorizon: 1 }
    const result = evaluate(bundleEvidence(), { policy })
    expect(result.transparency).toBe(TRANSPARENCY_NOT_CHECKED)
    expect(result.corroboration).toBe(CORROBORATION_NONE)
    expect(result.warnings).toEqual(['post_horizon_unanchored'])
  })

  it('applies the horizon cap when the anchor is too late', () => {
    const { evidence: anchorsEvidence, policy: policyBase, headerTime } = workingOtsEvidence(CP_BUNDLE3)
    const policy: AnchorPolicy = { pinnedHeaders: policyBase.pinnedHeaders, crqcHorizon: headerTime - 1 }
    const evidence = bundleEvidence({ anchors: anchorsEvidence })
    const result = evaluate(evidence, { policy })
    expect(result.transparency).toBe(TRANSPARENCY_NOT_CHECKED)
    expect(result.warnings).toEqual(['post_horizon_unanchored'])
  })

  it('does not cap when crqc_horizon is null', () => {
    const result = evaluate(bundleEvidence(), { policy: noHorizonPolicy() })
    expect(result.transparency).toBe(TRANSPARENCY_LOGGED)
    expect(result.warnings).toEqual([])
  })

  it('the horizon cap overrides prior logged-anchor state (rfc3161-only anchor is never PQ-surviving)', () => {
    const evidence = bundleEvidence({
      anchors: { checkpoint: CP_BUNDLE3, proofs: [{ kind: 'rfc3161', token_b64: 'b3BhcXVl' }] },
    })
    const policy: AnchorPolicy = { pinnedHeaders: {}, crqcHorizon: 1700000000 }
    const result = evaluate(evidence, { policy })
    expect(result.transparency).toBe(TRANSPARENCY_NOT_CHECKED)
    expect(result.warnings).toEqual([
      'rfc3161 token accepted as opaque classical evidence, carries no post-horizon weight',
      'post_horizon_unanchored',
    ])
  })

  it('surfaces anchor warnings on failed anchor evidence without failing the base standing (anchors are non-fatal)', () => {
    const evidence = bundleEvidence({ anchors: { checkpoint: CP_BUNDLE3, proofs: 'not-a-list' } })
    const result = evaluate(evidence)
    expect(result.transparency).toBe(TRANSPARENCY_LOGGED)
    expect(result.warnings).toEqual(['evidence.proofs must be a list, got str'])
  })
})

// --------------------------------------------------------------------------
// NEVER raises on malformed evidence.
// --------------------------------------------------------------------------

describe('evaluateTransparency: never throws on malformed evidence', () => {
  it.each([null, [], 'not-a-dict', 42, true])('non-object evidence (%s)', (bad) => {
    const result = evaluate(bad)
    expect(result.transparency).toBe(TRANSPARENCY_NOT_CHECKED)
    expect(result.warnings).toEqual(['evidence_invalid'])
  })

  it('never throws when required fields are missing', () => {
    const result = evaluate({})
    expect(result.transparency).toBe(TRANSPARENCY_NOT_CHECKED)
    expect(result.warnings).toEqual(['entry_invalid'])
  })

  it('confines a hostile evidence property getter', () => {
    const hostile = new Proxy(bundleEvidence(), {
      get(): never {
        throw new Error('hostile get')
      },
      has(): boolean {
        throw new Error('hostile has')
      },
    })
    const result = evaluate(hostile)
    expect(result.transparency).toBe(TRANSPARENCY_NOT_CHECKED)
    expect(result.corroboration).toBe(CORROBORATION_NONE)
    expect(result.warnings).toEqual(['evidence_evaluation_failed'])
  })
})

// --------------------------------------------------------------------------
// Trusted-arg validation: throws TransparencyError, never degrades.
// --------------------------------------------------------------------------

describe('evaluateTransparency: trusted-arg validation', () => {
  it('throws on non-list logKeys', () => {
    // eslint-disable-next-line @typescript-eslint/no-explicit-any
    expect(() => evaluate(bundleEvidence(), { logKeys: 'not-a-list' as any })).toThrow(TransparencyError)
  })

  it('throws on a logKeys list with a non-LogKey element', () => {
    // eslint-disable-next-line @typescript-eslint/no-explicit-any
    expect(() => evaluate(bundleEvidence(), { logKeys: [HK_A, 'x'] as any })).toThrow(TransparencyError)
  })

  it('throws on a malformed log_key field', () => {
    const malformedKey: LogKey = { origin: ORIGIN, name: LOG_NAME, ed25519Pub: enc.encode('too-short'), mldsaPub: HK_A.mldsaPub }
    expect(() => evaluate(bundleEvidence(), { logKeys: [malformedKey] })).toThrow(TransparencyError)
  })

  it('throws on a non-str expected_origin', () => {
    // eslint-disable-next-line @typescript-eslint/no-explicit-any
    expect(() => evaluate(bundleEvidence(), { expectedOrigin: 123 as any })).toThrow(TransparencyError)
  })

  it('throws on an empty expected_origin', () => {
    expect(() => evaluate(bundleEvidence(), { expectedOrigin: '' })).toThrow(TransparencyError)
  })

  it('throws on a non-AnchorPolicy', () => {
    // eslint-disable-next-line @typescript-eslint/no-explicit-any
    expect(() => evaluate(bundleEvidence(), { policy: 'not-a-policy' as any })).toThrow(TransparencyError)
  })

  it('throws on malformed policy.pinnedHeaders', () => {
    // eslint-disable-next-line @typescript-eslint/no-explicit-any
    const malformedPolicy = { pinnedHeaders: [], crqcHorizon: null } as any
    expect(() => evaluate(bundleEvidence(), { policy: malformedPolicy })).toThrow(TransparencyError)
  })

  it('throws on a non-object expected_entry', () => {
    // eslint-disable-next-line @typescript-eslint/no-explicit-any
    expect(() => evaluate(bundleEvidence(), { expectedEntry: 'not-a-dict' as any })).toThrow(TransparencyError)
  })

  it('throws on a schema-invalid expected_entry', () => {
    expect(() => evaluate(bundleEvidence(), { expectedEntry: { type: 'receipt' } })).toThrow(TransparencyError)
  })
})

// --------------------------------------------------------------------------
// Module contract: CORROBORATION_WITNESSED is defined but unreachable.
// --------------------------------------------------------------------------

describe('CORROBORATION_WITNESSED', () => {
  it('is defined', () => {
    expect(CORROBORATION_WITNESSED).toBe('witnessed')
  })

  it('is never returned across representative decision-order branches', () => {
    const base = evaluate(bundleEvidence())

    const consistent = evaluate(bundleEvidence({ prior_checkpoint: CP_PRIOR2, consistency_proof: [...CONSISTENCY_PROOF_2TO3] }))

    const { evidence: anchorsEvidence, policy } = workingOtsEvidence(CP_BUNDLE3)
    const anchored = evaluate(bundleEvidence({ anchors: anchorsEvidence }), { policy })

    const capped = evaluate(bundleEvidence(), { policy: { pinnedHeaders: {}, crqcHorizon: 1 } })

    for (const result of [base, consistent, anchored, capped]) {
      expect(result.corroboration).not.toBe(CORROBORATION_WITNESSED)
    }
  })
})

function receiptPayload(): JsonObject {
  return parse({
    attest_version: '0.1', issued_at: '2025-06-01T00:00:00Z', receipt_id: '01J000000000000000000000AA',
    supersedes: null,
    issuer: { display_name: 'Store', id: RECEIPT_ISSUER },
    work: { title: 'T', publisher: 'P', identifiers: { issuer_sku: 'X' } },
    license: { grant: 'perpetual', revocability: 'policy', transferable: false, drm: 'drm-bound', terms_uri: 'https://x/t', legal_text_sha256: 'a'.repeat(64) },
    buyer: { commitment: 'A'.repeat(43), identifier_type: 'email', pubkey: null },
    survivability: { end_of_life: 'none', eol_commitment_sha256: null, eol_commitment_uri: null, redownload_right: false },
  })
}

function envelopeV1(): { payload: JsonObject; signatures: JsonValue[] } {
  return { payload: receiptPayload(), signatures: [parse({ kid: RECEIPT_KID, alg: 'Ed25519', sig: RECEIPT_SIG_B64U })] }
}
function envelopeV2(): { payload: JsonObject; signatures: JsonValue[] } {
  return { payload: receiptPayload(), signatures: [parse({ kid: NEW_KID, alg: 'Ed25519', sig: RECEIPT_SIG_V2_B64U })] }
}
function envelopeBytes(envelope: unknown): Uint8Array {
  return enc.encode(JSON.stringify(envelope))
}

function manifestV1(): JsonObject {
  return parse({
    issuer: RECEIPT_ISSUER, manifest_version: 1, issued_at: '2026-01-01T00:00:00Z',
    keys: [{ kid: RECEIPT_KID, pub: b64uEncode(RECEIPT_PUB), valid_from: '2025-01-01T00:00:00Z', valid_to: null, status: 'active' }],
    manifest_signature: { kid: RECEIPT_KID, sig: MANIFEST_V1_SIG_B64U },
  })
}
function manifestCompromised(): JsonObject {
  return parse({
    issuer: RECEIPT_ISSUER, manifest_version: 1, issued_at: '2026-01-01T00:00:00Z',
    keys: [{ kid: RECEIPT_KID, pub: b64uEncode(RECEIPT_PUB), valid_from: '2025-01-01T00:00:00Z', valid_to: null, status: 'compromised' }],
    manifest_signature: { kid: RECEIPT_KID, sig: MANIFEST_V1_SIG_B64U },
  })
}
function manifestV2(): JsonObject {
  return parse({
    issuer: RECEIPT_ISSUER, manifest_version: 2, issued_at: '2026-01-02T00:00:00Z',
    keys: [
      { kid: RECEIPT_KID, pub: b64uEncode(RECEIPT_PUB), valid_from: '2025-01-01T00:00:00Z', valid_to: null, status: 'active' },
      { kid: NEW_KID, pub: b64uEncode(NEW_PUB), valid_from: '2025-01-01T00:00:00Z', valid_to: null, status: 'active' },
    ],
    manifest_signature: { kid: RECEIPT_KID, sig: MANIFEST_V2_SIG_B64U },
  })
}

function receiptTrustStore(manifest: JsonObject, chains?: Record<string, JsonObject[]>): TrustStore {
  const store: TrustStore = { manifests: { [RECEIPT_ISSUER]: manifest }, provenance: { [RECEIPT_ISSUER]: 'tls' } }
  if (chains) store.chains = chains
  return store
}

const KM_ENTRY_V1 = { type: 'key-manifest', issuer: RECEIPT_ISSUER, manifest_version: 1n, manifest_sha256: MANIFEST_SHA256_V1 }
const KM_ENTRY_V2 = { type: 'key-manifest', issuer: RECEIPT_ISSUER, manifest_version: 2n, manifest_sha256: MANIFEST_SHA256_V2 }

/** A minimal one-leaf log holding exactly `entry` — trivial (empty)
 * inclusion proof, tree_size=1. `entry` carries `bigint` for
 * manifest_version (this is the bigint-typed `JsonValue` convention
 * verify()'s public `transparency` option uses, matching every other
 * JSON-serializable input on this verifier's public surface — see
 * verify.ts's module comment). */
function singleEntryEvidence(entry: Record<string, unknown>, checkpointText: string): Record<string, unknown> {
  return { entry: { ...entry }, leaf_index: 0n, tree_size: 1n, inclusion_proof: [], checkpoint: checkpointText }
}

describe('verify(): Stage 2 integration', () => {
  it('defaults to not_checked when evidence is absent (zero-behavior-change)', () => {
    const result = verify(envelopeBytes(envelopeV1()), receiptTrustStore(manifestV1()))
    expect(result.transparency).toBe(TRANSPARENCY_NOT_CHECKED)
    expect(result.corroboration).toBe(CORROBORATION_NONE)
    expect(result.manifest_freshness).toBe('not_checked')
    expect(result.signature).toBe('valid')
    expect(result.errors).toEqual([])
  })

  it('a valid receipt claim reports logged', () => {
    const evidence = singleEntryEvidence(RECEIPT_ENTRY, CP_RECEIPT1)
    const result = verify(envelopeBytes(envelopeV1()), receiptTrustStore(manifestV1()), null, null, undefined as unknown as number, {
      transparency: evidence,
      logKeys: [HK_A],
      anchorPolicy: noHorizonPolicy(),
    })
    expect(result.transparency).toBe(TRANSPARENCY_LOGGED)
    expect(result.corroboration).toBe(CORROBORATION_LOGGED)
    expect(result.manifest_freshness).toBe('not_checked') // a receipt claim, not a key-manifest claim
    expect(result.signature).toBe('valid')
    expect(result.errors).toEqual([])
  })

  it('a valid key-manifest claim reports logged and freshness', () => {
    const evidence = singleEntryEvidence(KM_ENTRY_V1, CP_KM_V1_1)
    const result = verify(envelopeBytes(envelopeV1()), receiptTrustStore(manifestV1()), null, null, undefined as unknown as number, {
      transparency: evidence,
      logKeys: [HK_A],
      anchorPolicy: noHorizonPolicy(),
    })
    expect(result.transparency).toBe(TRANSPARENCY_LOGGED)
    expect(result.corroboration).toBe(CORROBORATION_LOGGED)
    expect(result.manifest_freshness).toBe('verified_as_of:1')
    expect(result.signature).toBe('valid')
    expect(result.errors).toEqual([])
  })

  it('a payload-only precommit hash is rejected as an entry mismatch (vector 28l)', () => {
    const payloadOnlyHash = Array.from(sha256(canonicalBytes(receiptPayload()))).map((b) => b.toString(16).padStart(2, '0')).join('')
    const entry = { type: 'receipt', issuer: RECEIPT_ISSUER, core_sha256: payloadOnlyHash }
    // This entry doesn't match any real checkpoint (payload-only hash was
    // never logged) — reuse CP_RECEIPT1 purely as a structurally valid
    // checkpoint; the mismatch is caught at the entry-comparison step
    // (before checkpoint verification even needs to succeed against this
    // specific entry).
    const evidence = { entry, leaf_index: 0n, tree_size: 1n, inclusion_proof: [], checkpoint: CP_RECEIPT1 }
    const result = verify(envelopeBytes(envelopeV1()), receiptTrustStore(manifestV1()), null, null, undefined as unknown as number, {
      transparency: evidence,
      logKeys: [HK_A],
      anchorPolicy: noHorizonPolicy(),
    })
    expect(result.transparency).toBe(TRANSPARENCY_NOT_CHECKED)
    expect(result.corroboration).toBe(CORROBORATION_NONE)
    expect(result.warnings).toEqual(['transparency_entry_mismatch', 'license.drm is drm-bound (design vector 18)'])
    expect(result.signature).toBe('valid') // the receipt itself is unaffected
  })

  it('a compromised key stays invalid despite logged transparency (design fix 6 / vector 28i)', () => {
    const evidence = singleEntryEvidence(RECEIPT_ENTRY, CP_RECEIPT1)
    const result = verify(envelopeBytes(envelopeV1()), receiptTrustStore(manifestCompromised()), null, null, undefined as unknown as number, {
      transparency: evidence,
      logKeys: [HK_A],
      anchorPolicy: noHorizonPolicy(),
    })
    expect(result.signature).toBe('invalid')
    expect(result.errors.some((e) => e.includes('compromised'))).toBe(true)
    expect(result.transparency).toBe(TRANSPARENCY_LOGGED)
    expect(result.corroboration).toBe(CORROBORATION_LOGGED)
    // Signature verification short-circuits BEFORE step 5 (content
    // warnings) when the key is compromised, so no drm-bound warning here
    // (contrast the other integration tests, whose receipts verify fully).
    expect(result.warnings).toEqual([])
  })

  it('manifest v2 without a rotation chain caps corroboration to none', () => {
    const evidence = singleEntryEvidence(KM_ENTRY_V2, CP_KM_V2_1)
    // No `chains` entry supplied at all — the rotation chain back to v1 is omitted.
    const result = verify(envelopeBytes(envelopeV2()), receiptTrustStore(manifestV2()), null, null, undefined as unknown as number, {
      transparency: evidence,
      logKeys: [HK_A],
      anchorPolicy: noHorizonPolicy(),
    })
    expect(result.transparency).toBe(TRANSPARENCY_LOGGED)
    expect(result.corroboration).toBe(CORROBORATION_NONE)
    expect(result.manifest_freshness).toBe('verified_as_of:1')
    expect(result.warnings).toEqual(['corroboration_requires_rotation_chain', 'license.drm is drm-bound (design vector 18)'])
    expect(result.signature).toBe('valid')
  })

  it('manifest v2 with a verified rotation chain keeps corroboration logged', () => {
    const evidence = singleEntryEvidence(KM_ENTRY_V2, CP_KM_V2_1)
    const trustStore = receiptTrustStore(manifestV2(), { [RECEIPT_ISSUER]: [manifestV1(), manifestV2()] })
    const result = verify(envelopeBytes(envelopeV2()), trustStore, null, null, undefined as unknown as number, {
      transparency: evidence,
      logKeys: [HK_A],
      anchorPolicy: noHorizonPolicy(),
    })
    expect(result.transparency).toBe(TRANSPARENCY_LOGGED)
    expect(result.corroboration).toBe(CORROBORATION_LOGGED)
    expect(result.manifest_freshness).toBe('verified_as_of:1')
    expect(result.warnings).toEqual(['license.drm is drm-bound (design vector 18)'])
  })

  it('equivocation detected via verify() warns but leaves ok unaffected', () => {
    const evidence = bundleEvidence({ prior_checkpoint: CP_FORK2, consistency_proof: [...REAL_EXTENSION_PROOF] })
    // JsonValue convention: leaf_index/tree_size as bigint at the verify()
    // API boundary (see singleEntryEvidence's doc comment).
    evidence['leaf_index'] = 1n
    evidence['tree_size'] = 3n
    const result = verify(envelopeBytes(envelopeV1()), receiptTrustStore(manifestV1()), null, null, undefined as unknown as number, {
      transparency: evidence,
      logKeys: [HK_A],
      anchorPolicy: noHorizonPolicy(),
    })
    expect(result.transparency).toBe(TRANSPARENCY_EQUIVOCATION_DETECTED)
    expect(result.corroboration).toBe(CORROBORATION_NONE)
    expect(result.warnings).toEqual(['log_equivocation_detected', 'license.drm is drm-bound (design vector 18)'])
    expect(result.signature).toBe('valid')
    expect(result.errors).toEqual([]) // equivocation is informational — never an error
  })

  it('transparency evidence without config warns config_missing', () => {
    const evidence = singleEntryEvidence(RECEIPT_ENTRY, CP_RECEIPT1)
    const result = verify(envelopeBytes(envelopeV1()), receiptTrustStore(manifestV1()), null, null, undefined as unknown as number, {
      transparency: evidence,
    })
    expect(result.transparency).toBe(TRANSPARENCY_NOT_CHECKED)
    expect(result.corroboration).toBe(CORROBORATION_NONE)
    expect(result.warnings).toEqual(['transparency_config_missing', 'license.drm is drm-bound (design vector 18)'])
    expect(result.signature).toBe('valid')
  })

  it('an unrecognized claim type reports not_checked', () => {
    const evidence = singleEntryEvidence(RECEIPT_ENTRY, CP_RECEIPT1)
    ;(evidence['entry'] as Record<string, unknown>)['type'] = 'unknown-claim-type'
    const result = verify(envelopeBytes(envelopeV1()), receiptTrustStore(manifestV1()), null, null, undefined as unknown as number, {
      transparency: evidence,
      logKeys: [HK_A],
      anchorPolicy: noHorizonPolicy(),
    })
    expect(result.transparency).toBe(TRANSPARENCY_NOT_CHECKED)
    expect(result.corroboration).toBe(CORROBORATION_NONE)
    expect(result.warnings).toEqual(['transparency_claim_unresolvable', 'license.drm is drm-bound (design vector 18)'])
  })

  it('throws TransparencyError on log_keys with disagreeing origins', () => {
    const evidence = singleEntryEvidence(RECEIPT_ENTRY, CP_RECEIPT1)
    const otherKey: LogKey = { origin: 'different-log/2026', name: LOG_NAME, ed25519Pub: ed25519.getPublicKey(new Uint8Array(32).fill(3)), mldsaPub: new Uint8Array(1952) }
    expect(() =>
      verify(envelopeBytes(envelopeV1()), receiptTrustStore(manifestV1()), null, null, undefined as unknown as number, {
        transparency: evidence,
        logKeys: [HK_A, otherKey],
        anchorPolicy: noHorizonPolicy(),
      }),
    ).toThrow(TransparencyError)
  })

  it('confines hostile transparency-evidence materialization (JCS round-trip is the sole untrusted-evidence touch)', () => {
    const base = singleEntryEvidence(RECEIPT_ENTRY, CP_RECEIPT1)
    const hostile = new Proxy(base, {
      get(): never {
        throw new Error('hostile get')
      },
    })
    const result = verify(envelopeBytes(envelopeV1()), receiptTrustStore(manifestV1()), null, null, undefined as unknown as number, {
      transparency: hostile,
      logKeys: [HK_A],
      anchorPolicy: noHorizonPolicy(),
    })
    expect(result.transparency).toBe(TRANSPARENCY_NOT_CHECKED)
    expect(result.corroboration).toBe(CORROBORATION_NONE)
    expect(result.warnings).toEqual(['transparency_claim_unresolvable', 'license.drm is drm-bound (design vector 18)'])
    expect(result.signature).toBe('valid')
  })

  it('existing callers are unaffected by the new keyword-only params (zero-behavior-change)', () => {
    const result = verify(envelopeBytes(envelopeV1()), receiptTrustStore(manifestV1()))
    expect(result.signature).toBe('valid')
    expect(result.schema).toBe('valid')
    expect(result.revocation).toBe('unknown')
    expect(result.binding).toBe('not_checked')
    expect(result.trust).toBe('verified')
    expect(result.transparency).toBe('not_checked')
    expect(result.corroboration).toBe('none')
    expect(result.manifest_freshness).toBe('not_checked')
    expect(result.errors).toEqual([])
  })

  it('materializes a changing tree_size once before evaluation (kills a TOCTOU)', () => {
    let reads = 0
    const base = singleEntryEvidence(KM_ENTRY_V1, CP_KM_V1_1)
    const changing = new Proxy(base, {
      get(target, prop, receiver) {
        if (prop === 'tree_size') {
          reads += 1
          return reads === 1 ? 777n : 1n
        }
        return Reflect.get(target, prop, receiver)
      },
    })
    const result = verify(envelopeBytes(envelopeV1()), receiptTrustStore(manifestV1()), null, null, undefined as unknown as number, {
      transparency: changing,
      logKeys: [HK_A],
      anchorPolicy: noHorizonPolicy(),
    })
    // The one materialized value (777) reaches the evaluator too, so it
    // rejects the mismatch instead of reporting freshness for a different
    // later value (1).
    expect(reads).toBe(1)
    expect(result.transparency).toBe(TRANSPARENCY_NOT_CHECKED)
    expect(result.corroboration).toBe(CORROBORATION_NONE)
    expect(result.manifest_freshness).toBe('not_checked')
    expect(result.warnings).toEqual(['tree_size_mismatch', 'license.drm is drm-bound (design vector 18)'])
    expect(result.signature).toBe('valid')
  })

  it('caps oversized transparency evidence', () => {
    const evidence = singleEntryEvidence(RECEIPT_ENTRY, CP_RECEIPT1)
    evidence['padding'] = 'x'.repeat(10_000_000)
    const result = verify(envelopeBytes(envelopeV1()), receiptTrustStore(manifestV1()), null, null, undefined as unknown as number, {
      transparency: evidence,
      logKeys: [HK_A],
      anchorPolicy: noHorizonPolicy(),
    })
    expect(result.transparency).toBe(TRANSPARENCY_NOT_CHECKED)
    expect(result.corroboration).toBe(CORROBORATION_NONE)
    expect(result.manifest_freshness).toBe('not_checked')
    expect(result.warnings).toEqual(['transparency_claim_unresolvable', 'license.drm is drm-bound (design vector 18)'])
    expect(result.signature).toBe('valid')
  })

  it('counts transparency evidence caps by Unicode code points, not UTF-16 units', () => {
    const evidence = singleEntryEvidence(RECEIPT_ENTRY, CP_RECEIPT1)
    const padding = '🎉'.repeat(5_000_000)
    expect(padding.length).toBe(10_000_000)
    evidence['padding'] = padding
    const result = verify(envelopeBytes(envelopeV1()), receiptTrustStore(manifestV1()), null, null, undefined as unknown as number, {
      transparency: evidence,
      logKeys: [HK_A],
      anchorPolicy: noHorizonPolicy(),
    })
    expect(result.transparency).toBe(TRANSPARENCY_LOGGED)
    expect(result.corroboration).toBe(CORROBORATION_LOGGED)
    expect(result.manifest_freshness).toBe('not_checked')
    expect(result.warnings).toEqual(['license.drm is drm-bound (design vector 18)'])
    expect(result.signature).toBe('valid')
  })

  it('accepts evaluator max-scale anchor evidence (harmonization boundary)', () => {
    // The outer materialization cap must COVER what the anchor evaluator's
    // own inner caps accept: 64 OTS proofs of 64 ops with max-size operands
    // serialize past 2MB and must still verify end-to-end.
    const evidence = singleEntryEvidence(RECEIPT_ENTRY, CP_RECEIPT1)
    const noteBytes = parseCheckpoint(CP_RECEIPT1).noteBytes
    const headerTime = 1700000000
    const headerHash = '3a'.repeat(32)
    const operandHex = 'ab'.repeat(1024)
    const operand = h(operandHex)
    let acc = sha256(noteBytes)
    // JsonValue convention: every numeric field must be bigint at this
    // (pre-materialization) level, matching this verifier's other
    // JSON-serializable inputs — see singleEntryEvidence's doc comment.
    const ops: unknown[][] = []
    for (let i = 0; i < 32; i++) {
      ops.push(['append', operandHex])
      ops.push(['sha256'])
      acc = sha256(new Uint8Array([...acc, ...operand]))
    }
    const accHex = Array.from(acc).map((b) => b.toString(16).padStart(2, '0')).join('')
    const proof = { kind: 'ots', ops, header_merkle_root: accHex, header_time: BigInt(headerTime), header_hash: headerHash }
    evidence['anchors'] = { checkpoint: CP_RECEIPT1, proofs: Array.from({ length: 64 }, () => proof) }
    const serializedLen = JSON.stringify(evidence, (_k, v) => (typeof v === 'bigint' ? v.toString() : v)).length
    expect(serializedLen).toBeGreaterThan(1_000_000)
    expect(serializedLen).toBeLessThanOrEqual(10_000_000)

    const policy: AnchorPolicy = { pinnedHeaders: { [headerHash]: { headerHash, merkleRoot: accHex, time: headerTime } }, crqcHorizon: null }
    const result = verify(envelopeBytes(envelopeV1()), receiptTrustStore(manifestV1()), null, null, undefined as unknown as number, {
      transparency: evidence,
      logKeys: [HK_A],
      anchorPolicy: policy,
    })
    expect(result.transparency).toBe(`anchored_before:${iso8601(headerTime)}`)
    expect(result.corroboration).toBe(CORROBORATION_LOGGED)
    expect(result.warnings).toEqual(['license.drm is drm-bound (design vector 18)'])
    expect(result.signature).toBe('valid')
  })
})
